dtsPropsFor.Button:
/** Visual style. `white`/`ghost-light` are for dark photo/navy surfaces. */
variant?: "primary" | "ghost" | "white" | "ghost-light";
/** Control size. Both keep a 44px min touch target. */
size?: "md" | "sm";
/** Show a spinner and disable the control. */
loading?: boolean;
/** Internal path (`/contact`) renders a client-side link; `http`/`mailto`/`tel` renders an anchor; omit for a <button>. */
href?: string;
className?: string;
children: React.ReactNode;
type?: "button" | "submit" | "reset";
disabled?: boolean;
onClick?: React.MouseEventHandler;
/** Also accepts native <button>/<a> attributes (aria-*, target, rel, name, …). */

dtsPropsFor.Section:
/** Vertical rhythm: sm=strips, md=default, lg=dark statement blocks, xl=final page CTA (one per page). */
size?: "sm" | "md" | "lg" | "xl";
/** Background on the tonal ladder. `navy` is a navy→navy-deep gradient; both navy tones set white text. */
tone?: "light" | "warm" | "navy" | "navy-deep";
id?: string;
className?: string;
children: React.ReactNode;
/** Rendered element. Defaults to <section>. */
as?: "section" | "div";

dtsPropsFor.SectionHeader:
/** Kicker/eyebrow label above the title. */
tag?: string;
/** Heading text (rendered in Bebas Neue). */
title: string | React.ReactNode;
subtitle?: string;
/** Draw a short hairline rule above the tag. */
lineAbove?: boolean;
/** `dark` for navy/photo surfaces (white text + azure accent). */
tone?: "light" | "dark";
align?: "left" | "center";
/** `md` = text-h1, `lg` = text-display. */
titleSize?: "md" | "lg";
className?: string;

dtsPropsFor.GlassGrid:
/** Vertical mullion pitch in px. */
cellX?: number;
/** Horizontal mullion pitch in px. */
cellY?: number;
/** Line color (any CSS color). Defaults to the azure accent. */
color?: string;
/** Layer opacity. Never exceed 0.2 on light surfaces. */
opacity?: number;
lineWidth?: number;
className?: string;
style?: React.CSSProperties;
